{
  "name": "fibonacci",
  "description": "Hitung angka Fibonacci ke-n. Parameter: n (int)",
  "code": "def fibonacci(n: int) -> int:
    if n < 0:
        raise ValueError(f'n harus >= 0, dapat: {n}')
    if n <= 1:
        return n
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b"
}

{
  "name": "convert_temperature",
  "description": "Konversi suhu antar satuan. Parameter: value (float), from_unit (str: celsius|fahrenheit|kelvin), to_unit (str: celsius|fahrenheit|kelvin)",
  "code": "def convert_temperature(value: float, from_unit: str, to_unit: str) -> float:
    from_unit = from_unit.lower()
    to_unit = to_unit.lower()
    if from_unit == 'fahrenheit':
        celsius = (value - 32) * 5 / 9
    elif from_unit == 'kelvin':
        celsius = value - 273.15
    else:
        celsius = value
    if to_unit == 'fahrenheit':
        return celsius * 9 / 5 + 32
    elif to_unit == 'kelvin':
        return celsius + 273.15
    return celsius"
}

{
  "name": "is_weekend",
  "description": "Cek apakah tanggal tertentu adalah akhir pekan (Sabtu/Minggu). Parameter: date_str (str, format YYYY-MM-DD)",
  "code": "from datetime import datetime

def is_weekend(date_str: str) -> dict:
    dt = datetime.strptime(date_str, '%Y-%m-%d')
    day_name = dt.strftime('%A')
    is_we = dt.weekday() >= 5
    return {'date': date_str, 'day': day_name, 'is_weekend': is_we}"
}

